"""
adapters/prismrag.py — PrismRAG Source Adapter

Wraps PrismRAG's supported backends (pgvector, Chroma, Pinecone, Weaviate)
as read-only SourceAdapters for PrismResonance.

IMPORTANT: PrismResonance reads raw stored vectors from the source DB.
It does NOT apply PrismRAG's re-mapping on reads — that mapping was applied
at ingestion time and is already baked into the stored vectors.  PrismResonance
treats those stored vectors as its immutable amplitudes (A).

No PrismRAGPatch license is required for read operations — the adapters
below connect directly to the underlying databases.  The PrismRAG license
is only needed on the write / ingestion side.

Supported adapters
------------------
PgvectorSourceAdapter   — reads from a psycopg2/psycopg3 pgvector table
ChromaSourceAdapter     — reads from a chromadb Collection
"""

from __future__ import annotations

from typing import Iterator, List, Optional

import numpy as np

from .base import ChunkRecord, SourceAdapter


# ─────────────────────────────────────────────────────────────────────────────
# pgvector read-only adapter
# ─────────────────────────────────────────────────────────────────────────────

class PgvectorSourceAdapter(SourceAdapter):
    """
    Read-only access to a pgvector table.

    Connects via psycopg2 or psycopg3 (whichever is installed).
    Never issues INSERT, UPDATE, or DELETE.

    Parameters
    ----------
    dsn          : PostgreSQL connection string.
    table        : Table name (default: "embeddings").
    id_col       : Primary key column (default: "id").
    text_col     : Text content column (default: "content").
    vector_col   : Embedding column (default: "embedding").
    embedding_dim: Expected vector dimension.  If 0, auto-detected on first fetch.
    """

    def __init__(
        self,
        dsn: str,
        table: str = "embeddings",
        id_col: str = "id",
        text_col: str = "content",
        vector_col: str = "embedding",
        embedding_dim: int = 0,
    ) -> None:
        self._dsn       = dsn
        self._table     = table
        self._id_col    = id_col
        self._text_col  = text_col
        self._vec_col   = vector_col
        self._dim       = embedding_dim
        self._conn      = None

    def _get_conn(self):
        if self._conn is None:
            try:
                import psycopg2
                self._conn = psycopg2.connect(self._dsn)
            except ImportError:
                import psycopg
                self._conn = psycopg.connect(self._dsn)
        return self._conn

    def fetch(self, chunk_ids: List[str]) -> List[ChunkRecord]:
        if not chunk_ids:
            return []
        conn   = self._get_conn()
        cur    = conn.cursor()
        placeholders = ",".join(["%s"] * len(chunk_ids))
        cur.execute(
            f"SELECT {self._id_col}, {self._text_col}, {self._vec_col} "
            f"FROM {self._table} "
            f"WHERE {self._id_col} IN ({placeholders})",
            chunk_ids,
        )
        records = []
        for row in cur.fetchall():
            cid, text, raw_vec = row
            vec = np.array(raw_vec, dtype=np.float32)
            records.append(ChunkRecord(chunk_id=str(cid), text=text or "", vector=vec))
        return records

    def scan_batches(
        self,
        batch_size: int = 256,
        namespace: str = "",
    ) -> Iterator[List[ChunkRecord]]:
        conn = self._get_conn()
        cur  = conn.cursor(name="prism_scan")   # server-side cursor for streaming
        cur.execute(
            f"SELECT {self._id_col}, {self._text_col}, {self._vec_col} "
            f"FROM {self._table} ORDER BY {self._id_col}"
        )
        while True:
            rows = cur.fetchmany(batch_size)
            if not rows:
                break
            batch = []
            for cid, text, raw_vec in rows:
                vec = np.array(raw_vec, dtype=np.float32)
                batch.append(ChunkRecord(chunk_id=str(cid), text=text or "", vector=vec))
            yield batch
        cur.close()

    def count(self, namespace: str = "") -> int:
        conn = self._get_conn()
        cur  = conn.cursor()
        cur.execute(f"SELECT COUNT(*) FROM {self._table}")
        return cur.fetchone()[0]

    def close(self) -> None:
        if self._conn:
            try:
                self._conn.close()
            except Exception:
                pass
            self._conn = None


# ─────────────────────────────────────────────────────────────────────────────
# ChromaDB read-only adapter
# ─────────────────────────────────────────────────────────────────────────────

class ChromaSourceAdapter(SourceAdapter):
    """
    Read-only access to a ChromaDB collection.

    Parameters
    ----------
    collection   : An existing chromadb Collection object.
                   Obtain via: client.get_collection("my_collection")
    """

    def __init__(self, collection) -> None:
        self._col = collection

    def fetch(self, chunk_ids: List[str]) -> List[ChunkRecord]:
        if not chunk_ids:
            return []
        result = self._col.get(
            ids=chunk_ids,
            include=["documents", "embeddings", "metadatas"],
        )
        records = []
        for i, cid in enumerate(result["ids"]):
            emb  = result["embeddings"][i] if result.get("embeddings") else None
            doc  = result["documents"][i]  if result.get("documents")  else ""
            meta = result["metadatas"][i]  if result.get("metadatas")  else {}
            if emb is None:
                continue
            records.append(ChunkRecord(
                chunk_id=cid,
                text=doc or "",
                vector=np.array(emb, dtype=np.float32),
                metadata=meta,
            ))
        return records

    def scan_batches(
        self,
        batch_size: int = 256,
        namespace: str = "",
    ) -> Iterator[List[ChunkRecord]]:
        total  = self.count()
        offset = 0
        while offset < total:
            result = self._col.get(
                limit=batch_size,
                offset=offset,
                include=["documents", "embeddings", "metadatas"],
            )
            if not result["ids"]:
                break
            batch = []
            for i, cid in enumerate(result["ids"]):
                emb  = result["embeddings"][i] if result.get("embeddings") else None
                doc  = result["documents"][i]  if result.get("documents")  else ""
                meta = result["metadatas"][i]  if result.get("metadatas")  else {}
                if emb is None:
                    continue
                batch.append(ChunkRecord(
                    chunk_id=cid,
                    text=doc or "",
                    vector=np.array(emb, dtype=np.float32),
                    metadata=meta,
                ))
            yield batch
            offset += batch_size

    def count(self, namespace: str = "") -> int:
        return self._col.count()
